import pytest
import io
from pypykatz.__main__ import main
from pypykatz.utils.crypto.winhash import NETNTLMV2

# Tests for 'pypykatz crypto netntlmv2'
# This is the algorihtm used by Windows for authenticating with network services
# The format used is the same as hashcat (-m 5600) and Responder (https://github.com/lgandx/Responder/)

TESTS= {
    """ Tests to perform. 
        key = name of the test
        values = ( password, copy-paste of the full hash line as dumped by Responder )
    """
    'emptypass': ( '', 'empty::qemu-win11:03029db451c5af83:35E43E6D405A59E1D241CACBF38075D6:'),
    'lowercase': ( 'didier',
    'didier::qemu-win11:8c1ddf2d8b8ed86c:C168BC4D57A0165B114B5593A02E691B:'),
    'uppercase': ( 'PASSWORD',
    'Test::UPPERCASE:f78dea103e49b71a:DA08959B43AA01F026919AB33122F130:'),
    'specialchar': ( 'Passw0rd!',
    'GuEst!::qemu-win11:3014e7a211dd4241:7DBCE0A00567F4924D37D3875C547D68:'),
    'hashcat': ( 'hashcat', # as given by `hashcat -m 5600 --hash-info`
    '0UL5G37JOI0SX::6VB1IS0KA74:ebe1afa18b7fbfa6:aab8bf8675658dd2a939458a1077ba08:010100000000000031c8aa092510945398b9f7b7dde1a9fb00000000f7876f2b04b700')
}

def launchpypykatz(capsys, monkeypatch, stdin=None, argv=None, exception=None):
    """ Utility function to simulate launching pypykatz with specific arguments and stdin """
    if argv is not None:
        monkeypatch.setattr("sys.argv", argv)
    if stdin is not None:
        monkeypatch.setattr("sys.stdin", stdin)
    if exception is not None:
        with pytest.raises(exception):
            main()
    else:
        main()
    return capsys.readouterr()

def test_netntlmv2_present(capsys,monkeypatch):
    """ Tests if netntlmv2 keyword is present in pypykatz's help message """
    out,err=launchpypykatz(capsys,monkeypatch, argv=['pypykatz', 'crypto', '-h'], exception=SystemExit)
    assert 'netntlmv2' in out

@pytest.mark.parametrize('testname,values', TESTS.items())
def test_netntlmv2(capsys, monkeypatch, testname, values):
    """ Test different values of username, domain, password and check that the hash is correct."""
    common_args=['pypykatz', 'crypto', 'netntlmv2']
    password=values[0]
    string=values[1]
    (username, _, domain, challenge, hash, blob )=string.split(':')
    # Launch the function directly
    assert NETNTLMV2(username,password, domain, challenge, blob) == bytes.fromhex(hash)
    # Launch via main() and stdin
    out, err = launchpypykatz(capsys,monkeypatch,
                        argv=common_args + [password],
                        stdin=io.StringIO(string)
                        )
    assert hash.lower() in out


